import { execSync } from "child_process"; import fs from "fs";
const WP_USER=process.env.WP_USER, WP_PASS=process.env.WP_APP_PASS;
const BASE="https://dev.avesa.lt";
const AUTH="Basic "+Buffer.from(`${WP_USER}:${WP_PASS}`).toString("base64");
const repo=process.env.GH_REPO, tok=process.env.GH_TOKEN;
function commitB64(name,b64){ const url='https://api.github.com/repos/'+repo+'/contents/screenshots/'+name; let sha=''; try{ sha=JSON.parse(execSync('curl -s -H "Authorization: Bearer '+tok+'" "'+url+'?ref=main&t='+Date.now()+'"',{encoding:'utf8'})).sha||''; }catch(e){} const body={message:'dp13',branch:'main',content:b64}; if(sha) body.sha=sha; fs.writeFileSync('/tmp/cbdp13.json',JSON.stringify(body)); execSync('curl -s -o /dev/null -X PUT -H "Authorization: Bearer '+tok+'" -H "Accept: application/vnd.github+json" -d @/tmp/cbdp13.json "'+url+'"',{encoding:'utf8'}); }
function exec(cmd){ try{ return execSync(cmd,{encoding:'utf8',maxBuffer:300000000,timeout:40000}); }catch(e){ return 'EXC:'+e.message; } }
const pcode=Buffer.from("",'base64').toString('utf8').trim();
(async()=>{
  var out={};
  fs.writeFileSync('/tmp/b557.json', JSON.stringify({name:'PSC DEPLOY13', code:pcode, scope:'global', active:true}));
  exec('curl -sk -m 20 -X PUT -H "Authorization: '+AUTH+'" -H "Content-Type: application/json" --data-binary @/tmp/b557.json "'+BASE+'/wp-json/code-snippets/v1/snippets/557"');
  var r=exec('curl -sk -m 30 "'+BASE+'/?psc_deploy13=1&k=ps2026"');
  var m=r.match(/(\{.*\})/s); out.deploy=m?JSON.parse(m[0]):r.slice(0,150);
  exec('curl -sk -m 20 -X DELETE -H "Authorization: '+AUTH+'" "'+BASE+'/wp-json/code-snippets/v1/snippets/557"');
  exec('curl -sk -m 15 -o /dev/null -X POST -H "Authorization: '+AUTH+'" -H "Content-Type: application/json" -d \'{"status":"publish"}\' "'+BASE+'/wp-json/wp/v2/pages/34262"');
  await new Promise(r=>setTimeout(r,1200));
  var url = BASE+'/sprendimai/kraiko-pasirinkimas/';
  try{
    const { chromium } = await import('playwright');
    const b=await chromium.launch({args:['--no-sandbox']});
    const c=await b.newContext({ignoreHTTPSErrors:true,viewport:{width:1440,height:1000}});
    const p=await c.newPage();
    await p.goto(url+'?nc='+Date.now(),{waitUntil:'domcontentloaded',timeout:25000});
    await p.waitForTimeout(3000);
    out.h1=await p.evaluate(()=>{ var h=document.querySelector('.psc-sol-hero-title'); return h?h.textContent.trim():''; });
    out.grid3_cols=await p.evaluate(()=>{ var g=document.querySelector('.psc-sol-krypt-grid-3'); return g?getComputedStyle(g).gridTemplateColumns:'(nėra grid-3)'; });
    out.cards=await p.evaluate(()=>document.querySelectorAll('.psc-sol-krypt').length);
    out.footnote=await p.evaluate(()=>!!document.querySelector('.psc-sol-footnote'));
    out.addcart=await p.evaluate(()=>document.querySelectorAll('.psc-sol-krypt-grid-3 .add_to_cart_button').length);
    out.click_target=await p.evaluate(()=>{ var a=document.querySelector('.psc-sol-krypt-btn'); return a?a.href:''; });
    const buf=await p.screenshot({fullPage:true}); commitB64('kraiko_desktop.png', buf.toString('base64'));
    const cM=await b.newContext({ignoreHTTPSErrors:true,viewport:{width:390,height:844},isMobile:true,hasTouch:true});
    const pM=await cM.newPage();
    await pM.goto(url+'?nc='+Date.now(),{waitUntil:'domcontentloaded',timeout:25000});
    await pM.waitForTimeout(3000);
    const bufM=await pM.screenshot({fullPage:true}); commitB64('kraiko_mobile.png', bufM.toString('base64'));
    await cM.close();
    if(out.click_target){
      const cT=await b.newContext({ignoreHTTPSErrors:true,viewport:{width:1100,height:800}});
      const pT=await cT.newPage();
      await pT.goto(out.click_target,{waitUntil:'domcontentloaded',timeout:35000});
      await pT.waitForTimeout(4000);
      out.click_result=await pT.evaluate(()=>{ var rc=document.querySelector('.woocommerce-result-count'); return rc?rc.textContent.trim():''; });
      await cT.close();
    }
    await b.close();
  }catch(e){ out.err=e.message.slice(0,150); }
  exec('curl -sk -m 15 -o /dev/null -X POST -H "Authorization: '+AUTH+'" -H "Content-Type: application/json" -d \'{"status":"draft"}\' "'+BASE+'/wp-json/wp/v2/pages/34262"');
  commitB64('deploy13.json', Buffer.from(JSON.stringify(out),'utf8').toString('base64'));
  console.log(JSON.stringify(out).slice(0,300));
})();
